export async function GET(req: Request) {
  try {
    const { searchParams } = new URL(req.url);
    const purge = searchParams.get('purge') === '1';

    // Repart proprement de cette base (remplace l'ancienne import ARAB)
    await prisma.prixReference.deleteMany({ where: { source: SOURCE } });
    if (purge) {
      // Optionnel: retire aussi les catalogues génériques précédents
      await prisma.prixReference.deleteMany({ where: { source: { in: ['Catalogue 2026', 'Base initiale 2026'] } } });
    }

    let n = 0;
    // insertion par lots pour la performance
    const lot: any[] = [];
    for (const [corpsEtat, designation, unite, prixUnitaire] of BASE) {
      lot.push({ corpsEtat, designation, unite, prixUnitaire, source: SOURCE, region: 'National', annee: 2024 });
      if (lot.length >= 500) { await prisma.prixReference.createMany({ data: lot }); n += lot.length; lot.length = 0; }
    }
    if (lot.length) { await prisma.prixReference.createMany({ data: lot }); n += lot.length; }

    const total = await prisma.prixReference.count();
    return NextResponse.json({ ok: true, message: 'Base ARAB AGENCEMENT 2024 restaurée ✅ (prix HT)', importes: n, totalPrix: total });
  } catch (e: any) {
    return NextResponse.json({ ok: false, error: e.message }, { status: 500 });
  }
}
